/**
 * SPEC-024: hardening de UI — guard de doble submit de la card "Coste de IA"
 * (observación de QA de SPEC-021 cerrada aquí): con la persistencia en vuelo
 * el botón "Guardar" queda deshabilitado con spinner y no hay segundo envío;
 * al resolver vuelve a estar operativo.
 * Generated by QA Dev agent.
 */
import { fireEvent, render, screen, waitFor, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { Toaster } from '@/components/ui/sonner'
import { AiCostCard } from '@/components/settings/AiCostCard'
import type { AiCostSettings, DbResult } from '@/types/domain'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

function renderCard(): RenderResult {
  return render(
    <>
      <AiCostCard />
      <Toaster />
    </>
  )
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
})

describe('AiCostCard (guard de doble submit SPEC-024)', () => {
  // SPEC-024 · AC-06
  it('disables Guardar with an inline spinner while the save is in flight, ignores extra submits and re-enables on resolve', async () => {
    // Promesa controlada: la persistencia queda EN VUELO hasta resolverla
    let resolveSave!: (value: DbResult<AiCostSettings>) => void
    vi.mocked(mockApi.api.db.setAiCostSettings).mockReturnValue(
      new Promise<DbResult<AiCostSettings>>((resolve) => {
        resolveSave = resolve
      })
    )
    const user = userEvent.setup()
    renderCard()

    const input = await screen.findByLabelText('Límite por entrevista (USD)')
    await waitFor(() => expect(input).toBeEnabled())
    await user.type(input, '2.50')
    const saveButton = screen.getByRole('button', { name: 'Guardar' })
    await user.click(saveButton)

    // En vuelo: botón deshabilitado con spinner inline (patrón del resto de forms)
    await waitFor(() => expect(saveButton).toBeDisabled())
    expect(saveButton.querySelector('.animate-spin')).not.toBeNull()

    // Doble envío: con el botón (submit por defecto del form) deshabilitado,
    // ni el click del usuario ni el click directo disparan un segundo envío
    await user.click(saveButton).catch(() => undefined)
    fireEvent.click(saveButton)
    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).toHaveBeenCalledTimes(1)
    expect(vi.mocked(mockApi.api.db.setAiCostSettings)).toHaveBeenCalledWith({ limitUsd: 2.5 })

    // Al resolver: toast de éxito y botón operativo de nuevo (sin spinner)
    resolveSave({ ok: true, data: { limitUsd: 2.5 } })
    await waitFor(() => expect(saveButton).toBeEnabled())
    expect(saveButton.querySelector('.animate-spin')).toBeNull()
    expect((await screen.findAllByText('Ajustes guardados')).length).toBeGreaterThanOrEqual(1)
  })
})
